from pathlib import Path

root = Path(r"C:\Users\Gebruiker\Rezzerv_Github")
pre = root / "backend/app/receipt_ingestion/preprocessing/receipt_image_preprocessing.py"
req = root / "backend/requirements.txt"

pre.write_text('from __future__ import annotations\n\nfrom dataclasses import asdict, dataclass, field\nfrom io import BytesIO\nimport os\nfrom pathlib import Path\nfrom typing import Any\n\nfrom PIL import Image, ImageOps\n\ntry:\n    import cv2\n    import numpy as np\nexcept Exception:\n    cv2 = None\n    np = None\n\ntry:\n    from rembg import remove as rembg_remove\nexcept Exception:\n    rembg_remove = None\n\n\nIMAGE_SUFFIXES = {".jpg", ".jpeg", ".png", ".webp", ".bmp"}\nALPHA_THRESHOLD = 12\nMIN_MASK_PIXELS = 20000\nMIN_QUAD_AREA_RATIO = 0.12\n\n\n@dataclass\nclass ReceiptImagePreprocessingDecision:\n    preprocessing_step: str\n    selected_route: str\n    applied_steps: list[str]\n    fallback_reason: list[str]\n    perspective_normalization: dict[str, Any] | None\n    diagnostics: dict[str, Any] = field(default_factory=dict)\n\n    def to_dict(self) -> dict[str, Any]:\n        return asdict(self)\n\n\ndef _debug_dir() -> Path | None:\n    value = os.environ.get("REZZERV_RECEIPT_PREPROCESS_DEBUG_DIR")\n    if not value:\n        return None\n    path = Path(value)\n    path.mkdir(parents=True, exist_ok=True)\n    return path\n\n\ndef _save_debug(name: str, image: Image.Image, diagnostics: dict[str, Any]) -> None:\n    out = _debug_dir()\n    if out is None:\n        return\n    path = out / name\n    image.save(path)\n    diagnostics.setdefault("debug_files", []).append(str(path))\n\n\ndef _encode_png(image: Image.Image) -> bytes:\n    buf = BytesIO()\n    image.save(buf, format="PNG")\n    return buf.getvalue()\n\n\ndef _pil_to_bgr(image: Image.Image):\n    if cv2 is None or np is None:\n        return None\n    return cv2.cvtColor(np.array(image.convert("RGB")), cv2.COLOR_RGB2BGR)\n\n\ndef _bgr_to_pil(image) -> Image.Image:\n    return Image.fromarray(cv2.cvtColor(image, cv2.COLOR_BGR2RGB))\n\n\ndef _safe_original(file_bytes: bytes, reasons: list[str], diagnostics: dict[str, Any]) -> tuple[bytes, ReceiptImagePreprocessingDecision]:\n    try:\n        img = Image.open(BytesIO(file_bytes))\n        img = ImageOps.exif_transpose(img).convert("RGB")\n        _save_debug("00_input_original.png", img, diagnostics)\n        return _encode_png(img), ReceiptImagePreprocessingDecision(\n            "receipt_image_preprocessing",\n            "original_safe_fallback",\n            [],\n            reasons,\n            None,\n            diagnostics,\n        )\n    except Exception as exc:\n        reasons.append(f"fallback_decode_failed:{type(exc).__name__}")\n        return file_bytes, ReceiptImagePreprocessingDecision(\n            "receipt_image_preprocessing",\n            "original_bytes_fallback",\n            [],\n            reasons,\n            None,\n            diagnostics,\n        )\n\n\ndef _order_points(points):\n    rect = np.zeros((4, 2), dtype="float32")\n    s = points.sum(axis=1)\n    rect[0] = points[np.argmin(s)]\n    rect[2] = points[np.argmax(s)]\n    diff = np.diff(points, axis=1)\n    rect[1] = points[np.argmin(diff)]\n    rect[3] = points[np.argmax(diff)]\n    return rect\n\n\ndef _warp_four_points(image, points):\n    rect = _order_points(points.astype("float32"))\n    tl, tr, br, bl = rect\n    width_a = np.linalg.norm(br - bl)\n    width_b = np.linalg.norm(tr - tl)\n    max_width = int(max(width_a, width_b))\n    height_a = np.linalg.norm(tr - br)\n    height_b = np.linalg.norm(tl - bl)\n    max_height = int(max(height_a, height_b))\n    if max_width < 250 or max_height < 500:\n        return None, {"reject": "warped_size_too_small", "max_width": max_width, "max_height": max_height}\n    dst = np.array([[0, 0], [max_width - 1, 0], [max_width - 1, max_height - 1], [0, max_height - 1]], dtype="float32")\n    matrix = cv2.getPerspectiveTransform(rect, dst)\n    warped = cv2.warpPerspective(image, matrix, (max_width, max_height), borderMode=cv2.BORDER_REPLICATE)\n    if warped.shape[1] > warped.shape[0]:\n        warped = cv2.rotate(warped, cv2.ROTATE_90_COUNTERCLOCKWISE)\n    return warped, {"quad": rect.astype(float).round(2).tolist(), "output_size": [int(warped.shape[1]), int(warped.shape[0])]}\n\n\ndef _find_quad_from_alpha(alpha, diagnostics: dict[str, Any]):\n    if cv2 is None or np is None:\n        return None, "cv2_or_numpy_unavailable"\n    mask = (alpha > ALPHA_THRESHOLD).astype("uint8") * 255\n    kernel = np.ones((21, 21), np.uint8)\n    mask_closed = cv2.morphologyEx(mask, cv2.MORPH_CLOSE, kernel, iterations=2)\n    mask_closed = cv2.morphologyEx(mask_closed, cv2.MORPH_OPEN, np.ones((5, 5), np.uint8), iterations=1)\n    _save_debug("10_rembg_alpha_mask.png", Image.fromarray(mask), diagnostics)\n    _save_debug("11_receipt_silhouette_closed.png", Image.fromarray(mask_closed), diagnostics)\n    contours, _ = cv2.findContours(mask_closed, cv2.RETR_EXTERNAL, cv2.CHAIN_APPROX_SIMPLE)\n    diagnostics["geometry_contours_found"] = len(contours)\n    if not contours:\n        return None, "no_silhouette_contour"\n    contour = max(contours, key=cv2.contourArea)\n    area = float(cv2.contourArea(contour))\n    image_area = float(alpha.shape[0] * alpha.shape[1])\n    area_ratio = area / image_area if image_area else 0.0\n    diagnostics["largest_silhouette"] = {"area": area, "image_area": image_area, "area_ratio": area_ratio}\n    if area < MIN_MASK_PIXELS or area_ratio < MIN_QUAD_AREA_RATIO:\n        return None, "largest_silhouette_too_small"\n    contour_debug = np.zeros_like(mask_closed)\n    cv2.drawContours(contour_debug, [contour], -1, 255, 8)\n    _save_debug("20_largest_contour.png", Image.fromarray(contour_debug), diagnostics)\n    perimeter = cv2.arcLength(contour, True)\n    best = None\n    for epsilon in (0.01, 0.015, 0.02, 0.025, 0.03, 0.04, 0.06, 0.08):\n        approx = cv2.approxPolyDP(contour, epsilon * perimeter, True)\n        if len(approx) == 4:\n            best = approx.reshape(4, 2).astype("float32")\n            diagnostics["quad_detection"] = {"method": "approxPolyDP", "epsilon": epsilon}\n            break\n    if best is None:\n        rect = cv2.minAreaRect(contour)\n        best = cv2.boxPoints(rect).astype("float32")\n        diagnostics["quad_detection"] = {"method": "minAreaRect_fallback"}\n    quad_debug = np.zeros((alpha.shape[0], alpha.shape[1], 3), dtype=np.uint8)\n    cv2.drawContours(quad_debug, [best.astype("int32")], -1, (255, 255, 255), 10)\n    _save_debug("30_quad_detected.png", Image.fromarray(quad_debug), diagnostics)\n    return best, None\n\n\ndef _normalize_after_rembg(rgba: Image.Image, diagnostics: dict[str, Any]) -> tuple[Image.Image | None, dict[str, Any] | None, str | None]:\n    if cv2 is None or np is None:\n        return None, None, "cv2_or_numpy_unavailable"\n    alpha = np.array(rgba.getchannel("A"))\n    quad, reason = _find_quad_from_alpha(alpha, diagnostics)\n    if quad is None:\n        return None, None, reason or "quad_not_found"\n    white = Image.new("RGBA", rgba.size, (255, 255, 255, 255))\n    composed = Image.alpha_composite(white, rgba).convert("RGB")\n    _save_debug("12_rembg_composited_full.png", composed, diagnostics)\n    bgr = _pil_to_bgr(composed)\n    if bgr is None:\n        return None, None, "bgr_conversion_failed"\n    warped, perspective = _warp_four_points(bgr, quad)\n    if warped is None:\n        return None, perspective, perspective.get("reject") if perspective else "warp_failed"\n    warped_pil = _bgr_to_pil(warped)\n    _save_debug("40_perspective_warp.png", warped_pil, diagnostics)\n    w, h = warped_pil.size\n    max_side = max(w, h)\n    if max_side > 3200:\n        scale = 3200 / float(max_side)\n        warped_pil = warped_pil.resize((int(w * scale), int(h * scale)), Image.Resampling.LANCZOS)\n        diagnostics["resize_after_warp"] = {"from": [w, h], "to": [warped_pil.width, warped_pil.height]}\n    _save_debug("50_vertical_normalized.png", warped_pil, diagnostics)\n    gray = ImageOps.grayscale(warped_pil)\n    _save_debug("60_final_ocr_input.png", gray, diagnostics)\n    return warped_pil, perspective, None\n\n\ndef apply_receipt_image_preprocessing(file_bytes: bytes, filename: str) -> tuple[bytes, ReceiptImagePreprocessingDecision]:\n    diagnostics: dict[str, Any] = {"filename": filename}\n    suffix = Path(filename or "").suffix.lower()\n    if suffix and suffix not in IMAGE_SUFFIXES:\n        return file_bytes, ReceiptImagePreprocessingDecision("receipt_image_preprocessing", "original", [], ["unsupported_image_suffix"], None, diagnostics)\n    try:\n        original = Image.open(BytesIO(file_bytes))\n        original = ImageOps.exif_transpose(original).convert("RGB")\n        _save_debug("00_input_original.png", original, diagnostics)\n    except Exception as exc:\n        return file_bytes, ReceiptImagePreprocessingDecision("receipt_image_preprocessing", "original_bytes_fallback", [], [f"image_decode_failed:{type(exc).__name__}"], None, diagnostics)\n    if rembg_remove is None:\n        return _safe_original(file_bytes, ["rembg_unavailable"], diagnostics)\n    try:\n        rgba_bytes = rembg_remove(file_bytes)\n        rgba = Image.open(BytesIO(rgba_bytes)).convert("RGBA")\n        rgba = ImageOps.exif_transpose(rgba)\n        _save_debug("09_rembg_raw_rgba.png", rgba, diagnostics)\n    except Exception as exc:\n        return _safe_original(file_bytes, [f"rembg_failed:{type(exc).__name__}"], diagnostics)\n    normalized, perspective, reason = _normalize_after_rembg(rgba, diagnostics)\n    if normalized is None:\n        white = Image.new("RGBA", rgba.size, (255, 255, 255, 255))\n        neutralized = Image.alpha_composite(white, rgba).convert("RGB")\n        _save_debug("40_final_runtime_preprocessed.png", neutralized, diagnostics)\n        diagnostics["final_size"] = [neutralized.width, neutralized.height]\n        return _encode_png(neutralized), ReceiptImagePreprocessingDecision(\n            "receipt_image_preprocessing",\n            "R9-25A_rembg_geometry_failed_neutralized",\n            ["rembg_remove_background", "white_background_composite"],\n            [reason or "geometry_normalization_failed"],\n            perspective,\n            diagnostics,\n        )\n    _save_debug("40_final_runtime_preprocessed.png", normalized, diagnostics)\n    diagnostics["final_size"] = [normalized.width, normalized.height]\n    return _encode_png(normalized), ReceiptImagePreprocessingDecision(\n        "receipt_image_preprocessing",\n        "R9-25A_rembg_geometry_normalized",\n        ["rembg_remove_background", "receipt_silhouette_quad", "perspective_warp", "portrait_normalized"],\n        [],\n        perspective,\n        diagnostics,\n    )\n', encoding="utf-8")

requirements = req.read_text(encoding="utf-8")
